export function initializeDropZone(dropZoneElement, dotNetHelper) {
    function onDragOver(e) {
        e.preventDefault();
        e.stopPropagation();
        dropZoneElement.classList.add('drag-over');
    }

    function onDragLeave(e) {
        e.preventDefault();
        e.stopPropagation();
        dropZoneElement.classList.remove('drag-over');
    }

    function onDrop(e) {
        e.preventDefault();
        e.stopPropagation();
        dropZoneElement.classList.remove('drag-over');

        const files = Array.from(e.dataTransfer.files).map(f => ({
            name: f.name,
            size: f.size,
            type: f.type || 'application/octet-stream'
        }));

        dotNetHelper.invokeMethodAsync('OnFilesDropped', files);
    }

    dropZoneElement.addEventListener('dragover', onDragOver);
    dropZoneElement.addEventListener('dragleave', onDragLeave);
    dropZoneElement.addEventListener('drop', onDrop);

    return {
        dispose: () => {
            dropZoneElement.removeEventListener('dragover', onDragOver);
            dropZoneElement.removeEventListener('dragleave', onDragLeave);
            dropZoneElement.removeEventListener('drop', onDrop);
        }
    };
}

@implements IAsyncDisposable
@inject IJSRuntime JS

<div @ref="_dropZoneRef" class="drop-zone">
    <p>Drag &amp; drop files here</p>
</div>

@if (_droppedFiles.Count > 0)
{
    <ul class="file-list">
        @foreach (var entry in _droppedFiles)
        {
            <li class="file-entry">
                @if (entry.IsOversize)
                {
                    <div class="file-error">
                        <strong>@entry.Info.Name</strong> &mdash;
                        <span class="error-text">File exceeds 10 MB limit (@FormatSize(entry.Info.Size))</span>
                    </div>
                }
                else
                {
                    <div class="file-details">
                        <strong>@entry.Info.Name</strong> &mdash;
                        @FormatSize(entry.Info.Size) &mdash;
                        @entry.Info.Type
                    </div>
                }
                <button class="btn-remove" @onclick="() => RemoveFile(entry)">Remove</button>
            </li>
        }
    </ul>
}

@code {
    private const long MaxFileSizeBytes = 10L * 1024 * 1024;

    private ElementReference _dropZoneRef;
    private IJSObjectReference? _module;
    private IJSObjectReference? _dropZoneInstance;
    private DotNetObjectReference<FileDropZone>? _dotNetRef;

    private readonly List<DroppedFileEntry> _droppedFiles = new();

    [Parameter]
    public EventCallback<List<FileInfo>> OnFilesChanged { get; set; }

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            _module = await JS.InvokeAsync<IJSObjectReference>("import", "./js/fileDropZone.js");
            _dotNetRef = DotNetObjectReference.Create(this);
            _dropZoneInstance = await _module.InvokeAsync<IJSObjectReference>(
                "initializeDropZone", _dropZoneRef, _dotNetRef);
        }
    }

    [JSInvokable]
    public async Task OnFilesDropped(List<FileInfo> files)
    {
        foreach (var file in files)
        {
            _droppedFiles.Add(new DroppedFileEntry(file, file.Size > MaxFileSizeBytes));
        }

        await NotifyParent();
        StateHasChanged();
    }

    private async Task RemoveFile(DroppedFileEntry entry)
    {
        _droppedFiles.Remove(entry);
        await NotifyParent();
    }

    private Task NotifyParent()
    {
        var accepted = _droppedFiles
            .Where(e => !e.IsOversize)
            .Select(e => e.Info)
            .ToList();

        return OnFilesChanged.InvokeAsync(accepted);
    }

    private static string FormatSize(long bytes)
    {
        return bytes switch
        {
            < 1024 => $"{bytes} B",
            < 1024 * 1024 => $"{bytes / 1024.0:F1} KB",
            < 1024 * 1024 * 1024 => $"{bytes / (1024.0 * 1024):F1} MB",
            _ => $"{bytes / (1024.0 * 1024 * 1024):F1} GB"
        };
    }

    public async ValueTask DisposeAsync()
    {
        if (_dropZoneInstance is not null)
        {
            await _dropZoneInstance.InvokeVoidAsync("dispose");
            await _dropZoneInstance.DisposeAsync();
        }
        if (_module is not null)
        {
            await _module.DisposeAsync();
        }
        _dotNetRef?.Dispose();
    }

    private sealed record DroppedFileEntry(FileInfo Info, bool IsOversize);
}

.drop-zone {
    display: flex;
    align-items: center;
    justify-content: center;
    min-height: 160px;
    border: 2px dashed #6c757d;
    border-radius: 8px;
    background-color: #f8f9fa;
    color: #6c757d;
    font-size: 1.1rem;
    transition: border-color 0.2s, background-color 0.2s;
    cursor: default;
    padding: 1rem;
}

::deep .drop-zone.drag-over {
    border-color: #0d6efd;
    background-color: #e7f1ff;
    color: #0d6efd;
}

.file-list {
    list-style: none;
    padding: 0;
    margin-top: 1rem;
}

.file-entry {
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding: 0.5rem 0.75rem;
    border: 1px solid #dee2e6;
    border-radius: 4px;
    margin-bottom: 0.5rem;
    background: #fff;
}

.file-details {
    flex: 1;
}

.file-error {
    flex: 1;
}

.error-text {
    color: #dc3545;
    font-weight: 500;
}

.btn-remove {
    margin-left: 1rem;
    padding: 0.25rem 0.75rem;
    border: 1px solid #dc3545;
    border-radius: 4px;
    background: transparent;
    color: #dc3545;
    cursor: pointer;
    font-size: 0.875rem;
    transition: background-color 0.15s, color 0.15s;
}

.btn-remove:hover {
    background-color: #dc3545;
    color: #fff;
}

