.drop-zone {
    display: flex;
    align-items: center;
    justify-content: center;
    min-height: 160px;
    border: 2px dashed #6c757d;
    border-radius: 8px;
    background-color: #f8f9fa;
    color: #6c757d;
    font-size: 1.1rem;
    transition: border-color 0.2s, background-color 0.2s;
    cursor: default;
    padding: 1rem;
}

::deep .drop-zone.drag-over {
    border-color: #0d6efd;
    background-color: #e7f1ff;
    color: #0d6efd;
}

.file-list {
    list-style: none;
    padding: 0;
    margin-top: 1rem;
}

.file-entry {
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding: 0.5rem 0.75rem;
    border: 1px solid #dee2e6;
    border-radius: 4px;
    margin-bottom: 0.5rem;
    background: #fff;
}

.file-details {
    flex: 1;
}

.file-error {
    flex: 1;
}

.error-text {
    color: #dc3545;
    font-weight: 500;
}

.btn-remove {
    margin-left: 1rem;
    padding: 0.25rem 0.75rem;
    border: 1px solid #dc3545;
    border-radius: 4px;
    background: transparent;
    color: #dc3545;
    cursor: pointer;
    font-size: 0.875rem;
    transition: background-color 0.15s, color 0.15s;
}

.btn-remove:hover {
    background-color: #dc3545;
    color: #fff;
}

